  ('social-worker-moex-00201', 'social-worker', 'social-worker-moex-114-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關社會服務品質要素定義的敘述，下列何者錯誤？', '["持久性（durability）：在可用的資源內儘可能提供有效率的服務", "可近性（accessibility）：服務易被取得的或提供服務機構距離具近便的", "安全性（security）：能適切管理風險與危險", "公開（openness）：提供充分的資訊及決策透明"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:01+00:00", "source_pdf_sha1": "6c7bbd6c0843", "answer_pdf_sha1": "3cc1800551f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00202', 'social-worker', 'social-worker-moex-114-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關傳統一般組織與品質服務組織之差異，下列敘述何者錯誤？', '["一般組織時常藉由減少資源以抑制成本", "品質服務組織著重於問題之發現，而非預防", "品質服務組織視品質與服務效率的改善為組織集體的努力", "一般組織由制度經營，參與者處於被動之地位"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:01+00:00", "source_pdf_sha1": "6c7bbd6c0843", "answer_pdf_sha1": "3cc1800551f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00203', 'social-worker', 'social-worker-moex-114-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會福利機構在建構專業團隊後，對「人」的管理需注意之原則，下列敘述何者錯誤？', '["發展與運用遊戲規則", "為了團隊的人際和諧，管理者應暫時擱置人際衝突", "促使服務使用者參與", "管理者要能善用溝通、記錄"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:01+00:00", "source_pdf_sha1": "6c7bbd6c0843", "answer_pdf_sha1": "3cc1800551f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00204', 'social-worker', 'social-worker-moex-114-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有效的網絡治理的關鍵在於網絡管理，有關網絡管理的敘述，下列何者錯誤？', '["將不同的機構和利害關係人結合在一起，以一種新的跨域方式共同工作", "網絡關係必須能彈性因應目標的調整", "網絡關係必須能適切管理信任與風險", "網絡關係應避免因環境變異而調整"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:01+00:00", "source_pdf_sha1": "6c7bbd6c0843", "answer_pdf_sha1": "3cc1800551f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00205', 'social-worker', 'social-worker-moex-114-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '當面對衝突時，作為一個主管，可選擇避免衝突、迎戰、對抗或嘗試去解決衝突。為了期待能', '["規避或掩飾衝突", "避免偏袒任何一方", "認真傾聽", "建立信任  ⑤假設衝突會自然被解決  ⑥持續檢視事情是否已獲得實際改善"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:01+00:00", "source_pdf_sha1": "6c7bbd6c0843", "answer_pdf_sha1": "3cc1800551f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00206', 'social-worker', 'social-worker-moex-114-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '預算編列攸關組織服務的推動能否進行，社會工作者應注意預算編列原則，下列敘述何者正確？', '["為確保與組織服務的方向一致，與「年度業務計畫書」要有緊密關聯", "為避免經費提供者將預算打折，應寬估一成預算", "為確保董事會順利支持，應樂觀估算所有可能的收入", "為確保組織財務紀律與穩定，應確保收入大於支出"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:01+00:00", "source_pdf_sha1": "6c7bbd6c0843", "answer_pdf_sha1": "3cc1800551f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00207', 'social-worker', 'social-worker-moex-114-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在服務輸送系統中更積極的努力行銷，以增加現有服務的使用率，例如鼓勵既有的服務對象更頻 繁地使用服務，係屬下列何種社會行銷策略？', '["市場開發", "產品開發", "市場滲透", "多角化經營"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:01+00:00", "source_pdf_sha1": "6c7bbd6c0843", "answer_pdf_sha1": "3cc1800551f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00208', 'social-worker', 'social-worker-moex-114-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關社會福利機構募款之敘述，下列何者錯誤？', '["長期且穩定的募款是社會福利機構的營運基礎", "社會工作者是專業助人者，宜儘量避免參與募款工作", "募款時宜提供捐款人多樣的選擇管道", "社會福利機構應與捐款人建立長期且穩定的關係"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:01+00:00", "source_pdf_sha1": "6c7bbd6c0843", "answer_pdf_sha1": "3cc1800551f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00209', 'social-worker', 'social-worker-moex-114-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '非營利組織應該要充分掌握各類資訊，以利做出適當的決策。有關不同類型資訊的敘述，下列何 者正確？', '["服務訊息是敘述服務對象以及其重要他人的訊息，例如問題、歷史、服務狀況等", "個案訊息是機構內各單位提供給個案的服務人數、人次、服務類型等", "機構訊息是指機構內部資訊，包括年度收入狀況、員工平均學歷、以及機構使命等", "社區訊息是指機構所在區域的相關訊息，包括個案接受服務的期限、就業和服務結果的資料等"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:01+00:00", "source_pdf_sha1": "6c7bbd6c0843", "answer_pdf_sha1": "3cc1800551f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00210', 'social-worker', 'social-worker-moex-114-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關社會服務變革的敘述，下列何者正確？', '["計畫性變革是指可以預期組織內部將發生的變革，因此能未雨綢繆", "漸進式變革是指突然發生的變革，無法預期也無從準備", "由上而下的變革是指變革透過一段醞釀和一系列與主管討論後決定", "由下而上的變革易因不確定性而導致員工抗拒"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:01+00:00", "source_pdf_sha1": "6c7bbd6c0843", "answer_pdf_sha1": "3cc1800551f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
